// Normalize both trigger sources into a common format.
// executeWorkflowTrigger (WF1 auto): has conversationId, contactId, lead_score
// webhook (Dashboard manual): has conversationId, triggeredBy
let id, triggerType, triggeredBy;

// Try executeWorkflow trigger first
let executeData = null;
try { executeData = $('Handoff Input').first().json; } catch(e) {}

// Try webhook trigger
let webhookData = null;
try { webhookData = $('Dashboard Handoff Webhook').first().json; } catch(e) {}

if (executeData && (executeData.conversationId || executeData.id)) {
  id = executeData.conversationId || executeData.id;
  triggerType = 'score_threshold';
  triggeredBy = 'ai_system';
} else if (webhookData) {
  // n8n webhook v2: body is nested under .body key
  const body = (webhookData.body && webhookData.body.conversationId) ? webhookData.body : webhookData;
  id = body.conversationId || body.id;
  triggerType = 'manual';
  triggeredBy = body.triggeredBy || 'dashboard';
}

if (!id) throw new Error('conversationId bulunamadi. executeData: ' + JSON.stringify(executeData) + ' webhookData: ' + JSON.stringify(webhookData));

return [{ json: { id, trigger_type: triggerType, triggered_by: triggeredBy } }];

// Merge conversation data from Supabase with trigger metadata
const prepareData = $('Prepare Input').item.json;
const convRaw = $('Get Full Conversation').item.json;
const conv = Array.isArray(convRaw) ? convRaw[0] : convRaw;
return [{ json: {
  id: conv.id,
  contact_id: conv.contact_id,
  clinic_id: conv.clinic_id,
  lead_score: conv.lead_score || 0,
  current_stage: conv.current_stage,
  collected_data: conv.collected_data || {},
  lead_signals: conv.lead_signals || {},
  images_received: conv.images_received || 0,
  trigger_type: prepareData.trigger_type,
  triggered_by: prepareData.triggered_by
} }];

const convData = $('Merge Conv Data').item.json;
const messagesRaw = $('Get All Messages').item.json;
const messages = Array.isArray(messagesRaw) ? messagesRaw : [messagesRaw];

const messagesText = messages.filter(m => m && m.content).map(m => 
  `${m.role === 'user' ? 'HASTA' : 'ASİSTAN'}: ${m.content}`
).join('\n');

const summaryPrompt = [
  { role: 'system', content: `Sen bir satış analisti asistanısın. Hasta-asistan WhatsApp konuşmasını analiz et. HER ZAMAN TÜRKÇE yaz.\n\nJSON formatında yanıt ver:\n{\n  "summary": "2-3 cümlelik konuşma özeti",\n  "suggested_approach": "Satışcı bu hastayla nasıl konuşmalı? Hassas noktalar, öneriler"\n}` },
  { role: 'user', content: `Konuşma:\n${messagesText}\n\nToplanan Veriler: ${JSON.stringify(convData.collected_data || {})}\nLead Score: ${convData.lead_score || 0}` }
];

return [{ json: {
  ...convData,
  summaryPrompt,
  collectedData: convData.collected_data || {},
  leadSignals: convData.lead_signals || {},
  imagesReceived: convData.images_received || 0,
  score: convData.lead_score || 0
} }];

const aiResp = $input.item.json;
const prev = $('Build Summary Prompt').item.json;
let summary = '', approach = '';

try {
  const parsed = JSON.parse(aiResp.choices[0].message.content);
  summary = parsed.summary || 'Özet oluşturulamadı';
  approach = parsed.suggested_approach || 'Standart yaklaşım önerilir';
} catch(e) {
  summary = 'Özet oluşturulamadı';
  approach = 'Standart yaklaşım önerilir';
}

const cd = prev.collectedData || {};

const noteBody = `🤖 AI Qualification Raporu
━━━━━━━━━━━━━━━━━━━━━━━━━━━

📋 ÖZET
${summary}

👤 HASTA BİLGİLERİ
Ad: ${cd.name || 'Belirtilmedi'}
Hizmet: ${cd.interested_service || 'Belirtilmedi'}
Pain Point: ${cd.pain_point || 'Belirtilmedi'}
Timeline: ${cd.timeline || 'Belirtilmedi'}
Bütçe: ${cd.budget_awareness || 'Sorulmadı'}
Daha Önce: ${cd.previous_consultation || 'Belirtilmedi'}
Ön Görüşme: ${cd.preferred_consultation_type || 'Belirtilmedi'}
Tercih: ${cd.preferred_day_time || 'Belirtilmedi'}
Sağlık: ${cd.special_health_notes || 'Yok'}
${prev.imagesReceived > 0 ? '📎 Görsel: ' + prev.imagesReceived + ' adet' : ''}

📊 LEAD SCORE: ${prev.score}/100

🚀 KAYNAK: ${prev.trigger_type === 'manual' ? 'Manuel (Dashboard)' : 'AI Otomatik'}
${prev.triggered_by ? '👤 Tetikleyen: ' + prev.triggered_by : ''}

💡 ÖNERİLEN YAKLAŞIM
${approach}
━━━━━━━━━━━━━━━━━━━━━━━━━━━`;

return [{ json: { ...prev, summary, approach, noteBody } }];

